UPDATE card_collection
SET is_public = false
WHERE name = 'Столицы 50 популярных стран';

INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🇬🇧 Английский. Самые употребительные фразы для путешествий', 1, true,
        '35 фраз для аэропорта, отеля, ресторана и ориентирования в городе. На обложке – фраза, на содержании – перевод.')
;
INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id
        FROM card_collection
        WHERE name = '🇬🇧 Английский. Самые употребительные фразы для путешествий'
        LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('Hello, can you help me?', 'Здравствуйте, не могли бы вы мне помочь? – Вежливая просьба о помощи.'),
             ('Where is the nearest airport?', 'Где находится ближайший аэропорт? – Спросить дорогу.'),
             ('How much does a ticket to London cost?', 'Сколько стоит билет до Лондона? – В кассе или у водителя.'),
             ('I would like to book a room for two nights.', 'Я хотел бы забронировать номер на две ночи. – В отеле.'),
             ('What time does the train leave?', 'Во сколько отправляется поезд? – На вокзале.'),
             ('Could you call a taxi for me?', 'Не могли бы вы вызвать мне такси? – На ресепшн или у прохожего.'),
             ('Do you accept credit cards?', 'Вы принимаете кредитные карты? – В магазине, ресторане.'),
             ('I have a reservation under the name Smith.', 'У меня есть бронь на имя Смит. – При заселении в отель.'),
             ('Is breakfast included?', 'Завтрак включён? – В отеле.'),
             ('Where can I exchange money?', 'Где можно обменять деньги? – Обменник или банк.'),
             ('I need a doctor, please.', 'Мне нужен врач, пожалуйста. – Экстренная ситуация.'),
             ('Call the police!', 'Вызовите полицию! – Только в крайнем случае.'),
             ('I lost my passport.', 'Я потерял свой паспорт. – Для обращения в посольство.'),
             ('Can I see the menu, please?', 'Можно посмотреть меню, пожалуйста? – В ресторане.'),
             ('What do you recommend?', 'Что вы рекомендуете? – У официанта.'),
             ('The bill, please.', 'Счёт, пожалуйста. – В кафе/ресторане.'),
             ('Is there a free table?', 'Есть свободный столик? – В ресторане.'),
             ('How can I get to the city centre?', 'Как добраться до центра города? – У местных жителей.'),
             ('Does this bus go to the station?', 'Этот автобус идёт до вокзала? – У водителя или на остановке.'),
             ('What is the Wi-Fi password?', 'Какой пароль от Wi-Fi? – В отеле, кафе.'),
             ('Can you take a photo of us?', 'Не могли бы вы нас сфотографировать? – К прохожему.'),
             ('I am allergic to nuts.', 'У меня аллергия на орехи. – Предупредить в ресторане.'),
             ('Please speak slower.', 'Пожалуйста, говорите медленнее. – Когда не понимаете собеседника.'),
             ('Do you speak Russian?', 'Вы говорите по-русски? – Чтобы перейти на родной язык.'),
             ('What time is check-out?', 'Во сколько освобождать номер? – В отеле.'),
             ('Is there a pharmacy nearby?', 'Рядом есть аптека? – Для покупки лекарств.'),
             ('I would like to extend my stay.', 'Я хотел бы продлить своё пребывание. – На ресепшн.'),
             ('Where is the luggage storage?', 'Где камера хранения? – На вокзале, в аэропорту.'),
             ('Can I have a receipt?', 'Можно мне чек? – После оплаты.'),
             ('What is the exchange rate?', 'Какой курс обмена? – В обменнике.'),
             ('Is this seat taken?', 'Это место занято? – В поезде, автобусе, кафе.'),
             ('I need an adapter for the socket.', 'Мне нужен переходник для розетки. – В отеле.'),
             ('Where is the toilet?', 'Где туалет? – Самая нужная фраза :)')) AS cards(front_side, back_side);
INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🇬🇧 Английский. Самые употребительные бытовые фразы', 1, true,
        '35 повседневных фраз для общения, покупок, знакомства и решения мелких проблем.')
;
INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id
        FROM card_collection
        WHERE name = '🇬🇧 Английский. Самые употребительные бытовые фразы'
        LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('What time is it?', 'Который час? – Универсальный вопрос о времени.'),
             ('Could you repeat that, please?', 'Не могли бы вы повторить? – Когда не расслышали.'),
             ('I don''t understand.', 'Я не понимаю. – Признание в непонимании.'),
             ('How do you say this in English?', 'Как это будет по-английски? – Указывая на предмет.'),
             ('What does this word mean?', 'Что означает это слово? – Уточнение лексики.'),
             ('Can I use your phone?', 'Можно воспользоваться вашим телефоном? – Вежливая просьба.'),
             ('Sorry, I''m late.', 'Извините, я опоздал. – При опоздании.'),
             ('What is your name?', 'Как вас зовут? – Знакомство.'),
             ('My name is ...', 'Меня зовут ... – Представление.'),
             ('Nice to meet you.', 'Приятно познакомиться. – Стандартная фраза.'),
             ('How are you?', 'Как дела? – Приветствие.'),
             ('I''m fine, thank you.', 'Хорошо, спасибо. – Типичный ответ.'),
             ('See you later.', 'Увидимся позже. – Прощание.'),
             ('Have a nice day!', 'Хорошего дня! – Пожелание.'),
             ('Can you help me with this?', 'Можете помочь мне с этим? – Просьба о помощи.'),
             ('How much does it cost?', 'Сколько это стоит? – О цене товара.'),
             ('I would like to buy this.', 'Я хотел бы купить это. – В магазине.'),
             ('Do you have a larger size?', 'У вас есть размер побольше? – Примерка одежды.'),
             ('Where is the fitting room?', 'Где примерочная? – В магазине одежды.'),
             ('What time do you open/close?', 'Во сколько вы открываетесь/закрываетесь? – Режим работы.'),
             ('I''m looking for a supermarket.', 'Я ищу супермаркет. – Спросить дорогу.'),
             ('Can I pay by card?', 'Можно заплатить картой? – В любом магазине.'),
             ('I need a receipt.', 'Мне нужен чек. – После оплаты.'),
             ('Sorry, I didn''t mean that.', 'Извините, я не хотел этого. – Извинение за случайную грубость.'),
             ('It doesn''t matter.', 'Неважно. – В ответ на извинение или неудачный вариант.'),
             ('Let me think about it.', 'Дайте подумать. – Нужно время на решение.'),
             ('I agree with you.', 'Я согласен с вами. – Выражение согласия.'),
             ('I don''t think so.', 'Я так не думаю. – Вежливое несогласие.'),
             ('That sounds good.', 'Звучит неплохо. – Одобрение предложения.'),
             ('What do you want to eat?', 'Что ты хочешь поесть? – Дома или в гостях.'),
             ('I''m hungry/thirsty.', 'Я хочу есть/пить. – Бытовое состояние.'),
             ('Can I have a glass of water?', 'Можно стакан воды? – Простая просьба.'),
             ('Please pass me the salt.', 'Передайте мне соль, пожалуйста. – За столом.'),
             ('I need to do the laundry.', 'Мне нужно постирать бельё. – Домашнее дело.'),
             ('What''s the weather like today?',
              'Какая сегодня погода? – Для планирования дня.')) AS cards(front_side, back_side);
INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🇬🇧 Английский. Современный сленг', 1, true,
        '35 актуальных сленговых выражений (lit, GOAT, ghosting и др.) с переводом и примерами. Для продвинутого уровня.')
;
INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id FROM card_collection WHERE name = '🇬🇧 Английский. Современный сленг' LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('Lit', 'Круто, офигенно (о событии, вечеринке). "That party was lit!" – Вечеринка была отпад.'),
             ('GOAT', 'Greatest Of All Time – лучший за всё время. "MJ is the GOAT." – Майкл Джордан лучший.'),
             ('Salty', 'Обиженный, злой по мелочам. "Why are you so salty?" – Чего ты взъелся?'),
             ('Ghosting',
              'Игнорирование, исчезновение без объяснений (в переписке). "He ghosted me." – Он перестал отвечать.'),
             ('Flex', 'Понтоваться, выставлять напоказ. "He''s flexing his new car." – Хвастается тачкой.'),
             ('Low key', 'Скромно, неявно, но на самом деле. "I low key like that song." – Типа мне нравится.'),
             ('High key', 'Открыто, сильно, очень. "I high key love this show." – Обожаю этот сериал.'),
             ('Shade', 'Недоброжелательность, скрытый дисс. "Throwing shade at someone." – Бросать тень.'),
             ('Clout', 'Влияние, популярность (часто незаслуженная). "Chasing clout on TikTok." – Гнаться за хайпом.'),
             ('Bet', 'Согласен, договорились (как "окей"). "Let''s meet at 5." – "Bet!" – Идёт.'),
             ('Cap / No cap', 'Врать / без вранья. "No cap, that''s true." – Без брехни, правда.'),
             ('Drip', 'Стиль, крутая одежда (часто блестящая). "Check out his drip!" – Зацени его прикид.'),
             ('FOMO', 'Fear Of Missing Out – боязнь пропустить что-то интересное.'),
             ('Mood', 'Описывает настроение или ситуацию с которой отождествляешь себя.'),
             ('Simp', 'Парень, который слишком угодничает перед девушкой, "подкаблучник".'),
             ('Stan', 'Быть фанатом до безумия (песня Эминем). "I stan this singer." – Обожаю.'),
             ('Yeet', 'Возглас радости, выброс, бросок. Также "бросать с силой".'),
             ('Snacc', 'Привлекательный человек (съедобный). "She''s a snacc." – Она лакомство.'),
             ('Extra', 'Чрезмерный, театральный, переигрывающий. "You''re so extra." – Ты слишком переигрываешь.'),
             ('Savage', 'Беспощадный, хладнокровно-крутой. "That was savage!" – Жестоко, но круто.'),
             ('Tea', 'Сплетни, горячие новости. "Spill the tea." – Рассказывай всё как есть.'),
             ('Dead', 'Умираю со смеху. "I''m dead." – Падаю, умора.'),
             ('Shook', 'В шоке, потрясён. "I''m shook." – Я в ахуе (мягкий вариант).'),
             ('Woke', 'Просвещённый, осознающий социальные проблемы.'),
             ('Cancel culture', 'Культура отмены (бойкотирование публичной личности).'),
             ('Thirsty', 'Жаждущий внимания или секса. "Thirsty trap." – Слишком навязчивый.'),
             ('GOATed', 'Стать величайшим (от GOAT). "His performance was GOATed." – Легендарно.'),
             ('Fit', 'Образ, наряд (от outfit). "Nice fit!" – Классный прикид.'),
             ('Sus', 'Подозрительный (от suspicious). "That''s sus." – Что-то тут нечисто.'),
             ('Rent free', 'Кто-то постоянно в мыслях, "живёт бесплатно в голове".'),
             ('Bop', 'Очень хорошая песня, залипательный трек.'),
             ('Vibe', 'Атмосфера, настроение; "хорошо проводить время". "Good vibes only."'),
             ('Cringe', 'Испанский стыд, неловкость. "That''s so cringe." – Это кринж.'),
             ('Based', 'Правдивый, принципиальный, иногда "смелый" (консервативный сленг).'),
             ('Sheesh', 'Возглас восхищения или недоверия (часто с пританцовкой).')) AS cards(front_side, back_side);
INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🚑 Симптомы и первая помощь', 1, true,
        '50 неотложных состояний: от ушибов до сердечного приступа. Алгоритмы первой помощи по стандартам. На обложке – симптом, на содержании – первая помощь.')
;
INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id FROM card_collection WHERE name = '🚑 Симптомы и первая помощь' LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('🤕 Ушиб (гематома)',
              'Симптомы: боль, отёк, синяк. Первая помощь: холод (лёд/замороженные продукты, обёрнутые в ткань) на 15–20 мин, покой, возвышенное положение конечности. При сильной боли — обезболивающее.'),
             ('🩹 Порез (резаная рана)',
              'Симптомы: нарушение целостности кожи, кровотечение. Первая помощь: промыть чистой водой, удалить видимые загрязнения, остановить кровь (давящая повязка), обработать края антисептиком (не лить в рану!), наложить стерильную повязку.'),
             ('🔥 Ожог термический',
              'Симптомы: покраснение, волдыри, боль. Первая помощь: охладить под проточной водой 10–20 мин, накрыть влажной стерильной салфеткой, дать обезболивающее. Нельзя: мазать маслом, вскрывать волдыри, прикладывать лёд напрямую.'),
             ('⚡ Ожог электрический',
              'Симптомы: следы от тока, потеря сознания, нарушение ритма сердца. Первая помощь: обесточить пострадавшего (выключить рубильник, отбросить провод сухой палкой), при отсутствии дыхания — СЛР, вызвать скорую.'),
             ('🧊 Обморожение',
              'Симптомы: побеление кожи, потеря чувствительности, при отогревании — боль и отёк. Первая помощь: поместить в тёплое место, снять мокрую одежду, согреть конечность в воде 37–40°C, наложить сухую повязку. Нельзя: растирать снегом, использовать горячую воду.'),
             ('🦴 Перелом (закрытый)',
              'Симптомы: деформация конечности, неестественное положение, боль, отёк, невозможность движения. Первая помощь: обездвижить (шина из подручных средств), холод, вызвать скорую. Не вправлять отломки!'),
             ('🩸 Носовое кровотечение',
              'Симптомы: истечение крови из носа. Первая помощь: сесть, наклонить голову вперёд, зажать ноздри на 10–15 мин, холод на переносицу. Нельзя: запрокидывать голову (кровь стечёт в глотку).'),
             ('🏊 Утопление',
              'Симптомы: отсутствие дыхания, синюшность кожи. Первая помощь: извлечь из воды, очистить рот от ила/воды, провести СЛР (30 нажатий : 2 вдоха), вызвать скорую. Даже при восстановлении дыхания — госпитализация.'),
             ('🌡️ Тепловой удар',
              'Симптомы: головная боль, тошнота, покраснение кожи, учащённый пульс, потеря сознания. Первая помощь: перенести в тень/прохладу, снять лишнюю одежду, обтереть влажной тканью, дать прохладное питьё (если в сознании).'),
             ('💊 Отравление (пероральное)',
              'Симптомы: тошнота, рвота, боль в животе, диарея, головокружение. Первая помощь: промыть желудок (выпить 1–2 л воды и вызвать рвоту) только если пострадавший в сознании и это не едкие вещества/нефтепродукты, дать сорбенты (активированный уголь), вызвать скорую.'),
             ('🐝 Укус насекомого (аллергия)',
              'Симптомы: отёк, покраснение, зуд; при аллергии — крапивница, отёк горла, затруднение дыхания. Первая помощь: удалить жало (если есть), холод, антигистаминное (супрастин, зодак). При анафилаксии — адреналин (есть в аптечке), срочно вызвать скорую.'),
             ('🐍 Укус змеи',
              'Симптомы: две точки от клыков, боль, отёк, тошнота, слабость. Первая помощь: обездвижить конечность, холод, обильное питьё, срочно в больницу. Нельзя: отсасывать яд ртом, накладывать жгут, надрезать рану.'),
             ('💔 Сердечный приступ (инфаркт)',
              'Симптомы: давящая боль за грудиной, иррадиирущая в левую руку/челюсть, одышка, холодный пот, страх смерти. Первая помощь: вызвать скорую, посадить с опущенными ногами, дать аспирин (разжевать), нитроглицерин (если нет противопоказаний), обеспечить доступ воздуха.'),
             ('🧠 Инсульт',
              'Симптомы: асимметрия лица, слабость в руке/ноге, нарушение речи, головокружение. Тест УДАР (улыбка, движение, речь). Первая помощь: уложить на бок (на случай рвоты), вызвать скорую, не давать есть/пить.'),
             ('😰 Обморок (синкопе)',
              'Симптомы: внезапная потеря сознания, бледность, слабый пульс. Первая помощь: уложить, приподнять ноги, расстегнуть воротник, обеспечить свежий воздух, похлопать по щекам, дать понюхать нашатырь (если есть).'),
             ('😵 Сотрясение мозга',
              'Симптомы: головная боль, тошнота, рвота, кратковременная потеря памяти, двоение в глазах. Первая помощь: холод на голову, покой, наблюдение. При потере сознания или ухудшении — срочно к врачу.'),
             ('🫀 Судороги (эпилептический приступ)',
              'Симптомы: тонико-клонические сокращения мышц, потеря сознания, возможен прикус языка. Первая помощь: подложить мягкое под голову, убрать опасные предметы, запомнить время приступа. Нельзя: разжимать зубы, вставлять ложку. После приступа — повернуть на бок.'),
             ('🍖 Попадание инородного тела (поперхнулся)',
              'Симптомы: невозможность говорить/кашлять, посинение, хватание за горло. Первая помощь: приём Геймлиха (встать сзади, сжать кулак выше пупка, резко надавить внутрь и вверх). Если без сознания — СЛР и осмотр полости рта.'),
             ('🩸 Кровотечение венозное',
              'Симптомы: тёмная кровь вытекает равномерно. Первая помощь: давящая повязка ниже раны (если вена) или выше (в зависимости от локализации), возвышенное положение конечности, холод. При сильном — жгут ниже/выше (записывать время).'),
             ('❤️ Кровотечение артериальное',
              'Симптомы: алая кровь бьёт фонтаном. Первая помощь: немедленно прижать пальцем выше раны, наложить жгут (максимум на 1 час летом, 30 мин зимой), записать время, вызвать скорую.'),
             ('🩹 Закрытая травма живота',
              'Симптомы: боль, напряжение брюшной стенки, тошнота, возможен шок. Первая помощь: холод на живот, уложить с согнутыми коленями, не давать есть/пить, срочно в больницу. Не вправлять выпавшие органы!'),
             ('🤢 Пищевое отравление',
              'Симптомы: тошнота, рвота, диарея, боль в животе, температура. Первая помощь: промывание желудка (если не более 2 часов), сорбенты, обильное питьё (регидрон), голод. При кровавой рвоте/стуле — скорая.'),
             ('🥶 Переохлаждение',
              'Симптомы: дрожь, спутанность сознания, замедление пульса. Первая помощь: перенести в тепло, снять мокрую одежду, укутать, дать тёплое сладкое питьё (без алкоголя!), согревать постепенно.'),
             ('🌿 Отравление угарным газом',
              'Симптомы: головная боль, тошнота, слабость, покраснение кожи, потеря сознания. Первая помощь: вынести на свежий воздух, расстегнуть одежду, СЛР при остановке дыхания, срочно вызвать скорую.'),
             ('🤯 Черепно-мозговая травма',
              'Симптомы: потеря сознания, тошнота, рвота, кровь/прозрачная жидкость из носа/ушей. Первая помощь: уложить на бок (фиксируя голову), холод, не давать пить, срочно к нейрохирургу.'),
             ('🦷 Зубная боль',
              'Симптомы: ноющая или острая боль в зубе/десне. Первая помощь: прополоскать содой/солью, принять обезболивающее (ибупрофен), при отёке — холод, обратиться к стоматологу.'),
             ('👁️ Попадание инородного тела в глаз',
              'Симптомы: слезотечение, жжение, покраснение. Первая помощь: промыть чистой водой (не тереть!), удалить пинцетом только если видимо и на роговице — лучше к окулисту. При проникающем ранении — не трогать, стерильная повязка, скорая.'),
             ('🦻 Инородное тело в ухе',
              'Симптомы: боль, снижение слуха, шум. Первая помощь: при живом насекомом — залить маслом (оно всплывёт). При твёрдом предмете — не лезть пинцетом (может протолкнуть глубже). Только ЛОР.'),
             ('👃 Инородное тело в носу',
              'Симптомы: затруднение дыхания, неприятный запах. Первая помощь: попросить высморкаться (прикрыв здоровую ноздрю). Не пытаться извлечь пинцетом. К врачу.'),
             ('🧴 Химический ожог глаз',
              'Симптомы: жгучая боль, слезотечение, светобоязнь. Первая помощь: обильное промывание водой (не менее 15 мин), веки разомкнуть, срочно к офтальмологу.'),
             ('🩸 Ушиб грудной клетки',
              'Симптомы: боль при дыхании, отёк, гематома. Первая помощь: холод, полусидячее положение, ограничение движений. При одышке, кашле с кровью — скорая (возможен перелом рёбер с пневмотораксом).'),
             ('🚨 Пневмоторакс (открытый)',
              'Симптомы: рана в грудной клетке, через которую всасывается воздух, одышка, падение давления. Первая помощь: наложить окклюзионную повязку (клеёнка/пакет, заклеить с трёх сторон), вызвать скорую.'),
             ('🫁 Астматический приступ',
              'Симптомы: затруднённый выдох, свистящее дыхание, синюшность губ. Первая помощь: посадить, дать ингалятор (сальбутамол), расстегнуть воротник, обеспечить приток воздуха, при отсутствии эффекта — скорая.'),
             ('💊 Анафилактический шок',
              'Симптомы: резкая слабость, отёк лица/горла, крапивница, падение давления, потеря сознания. Первая помощь: уложить с приподнятыми ногами, ввести адреналин (если есть автоинжектор), антигистаминное, срочно вызвать скорую.'),
             ('🤒 Лихорадка (высокая температура)',
              'Симптомы: температура >39°C, озноб, ломота. Первая помощь: жаропонижающие (парацетамол, ибупрофен), обильное питьё, обтирание водой комнатной температуры (не спиртом!), лёгкая одежда.'),
             ('😖 Мигрень',
              'Симптомы: пульсирующая боль в одной половине головы, свето- и звукобоязнь, тошнота. Первая помощь: покой, тёмная тихая комната, холод на лоб, обезболивающие (ибупрофен, триптаны по назначению).'),
             ('🦵 Вывих',
              'Симптомы: неестественное положение сустава, боль, невозможность движения. Первая помощь: обездвижить (шина), холод, не вправлять самостоятельно! Вызвать скорую или доставить в травмпункт.'),
             ('🦶 Растяжение связок',
              'Симптомы: боль, отёк, гематома, но движение возможно. Первая помощь: покой (не нагружать), холод (первые 48 часов), тугая повязка (эластичный бинт), возвышенное положение.'),
             ('🐕 Укус собаки/кошки',
              'Симптомы: рваные раны, кровотечение. Первая помощь: промыть водой с мылом, обработать антисептиком, наложить повязку, обратиться к врачу (риск бешенства, столбняка).'),
             ('🧴 Отравление кислотой/щелочью',
              'Симптомы: ожог губ, рта, боль при глотании, рвота с кровью. Первая помощь: не вызывать рвоту! Дать выпить воды (1-2 стакана), молоко или яичный белок, срочно в больницу.'),
             ('🍄 Отравление грибами',
              'Симптомы: через 1-6 часов рвота, понос, боль в животе, возможна желтуха. Первая помощь: промывание желудка, сорбенты, обильное питьё, срочно в стационар (сохранить остатки грибов).'),
             ('🩸 Алкогольное отравление',
              'Симптомы: спутанное сознание, рвота, медленное дыхание, синюшность кожи. Первая помощь: уложить на бок (не захлебнулся рвотой), обеспечить доступ воздуха, при остановке дыхания — СЛР, вызвать скорую. Не давать кофе!'),
             ('💧 Обезвоживание',
              'Симптомы: сухость во рту, слабость, снижение мочеиспускания, головокружение. Первая помощь: дробное питьё (вода, регидрон), покой, избегать жары. При тяжёлой степени (потеря сознания) — капельницы (скорая).'),
             ('🌡️ Солнечный удар',
              'Симптомы: головная боль, тошнота, слабость, покраснение лица, учащённый пульс. Первая помощь: в тень, прохладный компресс на лоб, питьё, при ухудшении — скорая.'),
             ('🧠 Гипогликемия (низкий сахар)',
              'Симптомы: слабость, дрожь, потливость, голод, спутанность сознания (у диабетиков). Первая помощь: дать сахар, сладкий сок, конфету. Если без сознания — не лить в рот, ввести глюкагон (если есть), вызвать скорую.'),
             ('🩸 Гипергликемия (высокий сахар)',
              'Симптомы: сильная жажда, частое мочеиспускание, слабость, запах ацетона изо рта. Первая помощь: дать пить (несладкое), вызвать скорую, не вводить инсулин самостоятельно без измерения сахара.'),
             ('🤱 Приступ эпилепсии (малый)',
              'Симптомы: «застывание» взгляда, автоматические движения, отсутствие реакции. Первая помощь: убрать опасные предметы, не будить, после приступа успокоить. Не требуется специальная помощь, кроме наблюдения.'),
             ('🦷 Кровотечение после удаления зуба',
              'Симптомы: выделение крови из лунки. Первая помощь: прикусить стерильный тампон (из бинта) на 20–30 мин, холод на щеку. Если не останавливается — к стоматологу.'),
             ('👶 Первая помощь при подавившемся ребёнке (до 1 года)',
              'Симптомы: ребёнок не может дышать/плакать, синеет. Первая помощь: положить на предплечье лицом вниз, наклонить, сделать 5 похлопываний по спине между лопатками, затем 5 толчков в грудину (пальцами). Чередовать. Вызвать скорую.'),
             ('💓 Остановка сердца (базовая СЛР)',
              'Симптомы: отсутствие сознания, дыхания, пульса на сонной артерии. Первая помощь: положить на твёрдую поверхность, 30 нажатий на центр грудной клетки (глубина 5–6 см, частота 100–120/мин), чередовать с 2 вдохами «рот в рот» (с зажатым носом). До приезда скорой или появления признаков жизни.')) AS cards(front_side, back_side);
INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🤵 Популярные актеры (определи по фото)', 1, true,
        '50 известных актёров с фотографиями. На содержании – дата рождения и известные роли. 💡 Картинки отображаются только во время тренировки.')
;
INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id FROM card_collection WHERE name = '🤵 Популярные актеры (определи по фото)' LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3769481/pub_5ff205b2f906b16872fdfaa9_5ff2067dfe4e686f6a3efe2c/scale_1200">Картинка</a>',
              'Джек Николсон (р. 1937). Легенда метода. Оскары: «Пролетая над гнездом кукушки», «Лучше не бывает». Блестяще сыграл Джокера в «Бэтмене» (1989).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3431141/pub_5ff205b2f906b16872fdfaa9_5ff206a6d1a90641ca0f630f/scale_1200">Картинка</a>',
              'Аль Пачино (р. 1940). Икона криминального кино. «Крёстный отец», «Лицо со шрамом», «Запах женщины» (Оскар). Его «Ха-а-а!» стало мемом.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3502647/pub_5ff205b2f906b16872fdfaa9_5ff206ecf906b16872ffdf23/scale_1200">Картинка</a>',
              'Дензел Вашингтон (р. 1954). Два Оскара («Тренировочный день», «Слава»). Выдающийся драматический актёр. «Гнев», «Ураган», «Равнина стрелка».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3507111/pub_5ff205b2f906b16872fdfaa9_5ff2070baf142f0b1773d75c/scale_1200">Картинка</a>',
              'Джонни Депп (р. 1963). Харизматичный эксцентрик. Роли: Джек Воробей («Пираты Карибского моря»), Эдвард Руки-ножницы, Вилли Вонка.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1881575/pub_5ff205b2f906b16872fdfaa9_5ff2072bf906b16872004405/scale_1200">Картинка</a>',
              'Гари Олдман (р. 1958). «Хамелеон» кино. Дракула, Сириус Блэк («Гарри Поттер»), Уинстон Черчилль («Тёмные времена» — Оскар).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1581245/pub_5ff205b2f906b16872fdfaa9_5ff20746af142f0b17742da9/scale_1200">Картинка</a>',
              'Харрисон Форд (р. 1942). Легенда блокбастеров. Хан Соло («Звёздные войны»), Индиана Джонс («Искатели потерянного ковчега»), бескомпромиссный герой.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1348874/pub_5ff205b2f906b16872fdfaa9_5ff208cdd1a90641ca128810/scale_1200">Картинка</a>',
              'Джим Керри (р. 1962). Король гротескной комедии. «Эйс Вентура», «Маска», «Тупой и ещё тупее». Позже раскрылся в драмах («Шоу Трумана»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4004066/pub_5ff205b2f906b16872fdfaa9_5ff20907af142f0b1776c521/scale_1200">Картинка</a>',
              'Джон Малкович (р. 1953). Интеллектуальный злодей и характерный актёр. «Быть Джоном Малковичем», «Опасные связи», «Красный воробей».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3414416/pub_5ff205b2f906b16872fdfaa9_5ff20923bb14d54ffbb11354/scale_1200">Картинка</a>',
              'Джон Траволта (р. 1954). Звезда диско и боевиков. «Лихорадка субботнего вечера», «Криминальное чтиво» (Танец), «Без лица».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3432422/pub_5ff205b2f906b16872fdfaa9_5ff2093ff906b16872035093/scale_1200">Картинка</a>',
              'Майкл Дуглас (р. 1944). Продюсер и актёр. «Уолл-стрит» (Оскар), «Основной инстинкт», «Падение олимпа». Сын Кирка Дугласа.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1545908/pub_5ff205b2f906b16872fdfaa9_5ff2095aaf142f0b17774e0d/scale_1200">Картинка</a>',
              'Николас Кейдж (р. 1964). Оскар за «Покидая Лас-Вегас». Снимается во всём: от «Без лица» до «Мэнди». Племянник Фрэнсиса Форда Копполы.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2804475/pub_5ff205b2f906b16872fdfaa9_5ff209a0f906b1687203ee59/scale_1200">Картинка</a>',
              'Роберт Дюваль (р. 1931). Ветеран. Оскар за «Нежное милосердие». «Крёстный отец», «Апокалипсис сегодня», «Судья».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1917356/pub_5ff205b2f906b16872fdfaa9_5ff209bed1a90641ca13f229/scale_1200">Картинка</a>',
              'Сэмюэл Л. Джексон (р. 1948). Самый кассовый актёр в истории. «Криминальное чтиво» (мистер Вульф), Ник Фьюри в Marvel. Матье.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3894718/pub_5ff205b2f906b16872fdfaa9_5ff209e6af142f0b177824b4/scale_1200">Картинка</a>',
              'Вуди Харрельсон (р. 1961). От «Народ против Ларри Флинта» до зомби-юмора («Добро пожаловать в Zомбилэнд»). Два Оскара номинации.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3769362/pub_5ff205b2f906b16872fdfaa9_5ff209f0fe4e686f6a4436ba/scale_1200">Картинка</a>',
              'Бен Кингсли (р. 1943). Оскар за «Ганди». Играл Шлёму в «Списке Шиндлера», также злодеев («Железный человек 3»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1066925/pub_5ff205b2f906b16872fdfaa9_5ff209f1f906b1687204737d/scale_1200">Картинка</a>',
              'Бен Аффлек (р. 1972). Режиссёр («Операция „Арго“» — Оскар). Актёр: «Умница Уилл Хантинг», Бэтмен в DCEU.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3533963/pub_5ff205b2f906b16872fdfaa9_5ff20a4cf906b16872050674/scale_1200">Картинка</a>',
              'Бенедикт Камбербэтч (р. 1976). Шерлок («Шерлок»), Доктор Стрэндж (Marvel). Оскар за «Игру в имитацию»? (нет, номинация).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3502647/pub_5ff205b2f906b16872fdfaa9_5ff20a6aaf142f0b1778ecd9/scale_1200">Картинка</a>',
              'Бенисио Дель Торо (р. 1967). Оскар за «Траффик». «Обычные подозреваемые», «Убить Билла», «Стражи Галактики» (Коллекционер).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3413906/pub_5ff205b2f906b16872fdfaa9_5ff20a8bf906b1687205661d/scale_1200">Картинка</a>',
              'Билл Мюррей (р. 1950). Икона комедии («Охотники за привидениями», «День сурка») и драм («Трудности перевода» — номинация на Оскар).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3769340/pub_5ff205b2f906b16872fdfaa9_5ff20aaff906b1687205a12d/scale_1200">Картинка</a>',
              'Билли Боб Торнтон (р. 1955). Оскар за сценарий («Фарго»). Роли: «Простой план», «Плохой Санта», сериал «Фарго».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2377661/pub_5ff205b2f906b16872fdfaa9_5ff20ac8fe4e686f6a4572ee/scale_1200">Картинка</a>',
              'Брэд Питт (р. 1963). Два Оскара (продюсер «12 лет рабства», актёр «Однажды в Голливуде»). «Бойцовский клуб», «Семь», «Троя».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3533963/pub_5ff205b2f906b16872fdfaa9_5ff20ae5af142f0b1779b14d/scale_1200">Картинка</a>',
              'Брэдли Купер (р. 1975). Многократный номинант на Оскар («Снайпер», «Звезда родилась»). «Мальчишник в Вегасе», «Стражи Галактики» (голос).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1640172/pub_5ff205b2f906b16872fdfaa9_5ff20b00af142f0b1779dc66/scale_1200">Картинка</a>',
              'Брюс Уиллис (р. 1955). Джон Макклейн («Крепкий орешек»). Легенда экшена. Также «Шестое чувство», «Криминальное чтиво».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1856484/pub_5ff205b2f906b16872fdfaa9_5ff20b26f906b1687206612c/scale_1200">Картинка</a>',
              'Вигго Мортенсен (р. 1958). Арагорн («Властелин колец»). Три номинации на Оскар («Капитан Фантастик», «Зелёная книга»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3001030/pub_5ff205b2f906b16872fdfaa9_5ff20b48d1a90641ca165c0e/scale_1200">Картинка</a>',
              'Вуди Аллен (р. 1935). Режиссёр-неврастеник, актёр. «Энни Холл» (Оскар), «Манхэттен». Стиль: интеллектуальная комедия.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3144955/pub_5ff205b2f906b16872fdfaa9_5ff20b6ad1a90641ca16917c/scale_1200">Картинка</a>',
              'Генри Кавилл (р. 1983). Супермен (DCEU), Ведьмак (Геральт из Ривии). Британский красавец, также «Агенты U.N.C.L.E.».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3505723/pub_5ff205b2f906b16872fdfaa9_5ff20b91bb14d54ffbb4d11c/scale_1200">Картинка</a>',
              'Деннис Хоппер (1936–2010). Культовый режиссёр («Беспечный ездок»), актёр («Синий вельвет», «Скорость»). Икона контркультуры.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1658056/pub_5ff205b2f906b16872fdfaa9_5ff20bc0fe4e686f6a4706a1/scale_1200">Картинка</a>',
              'Джаред Лето (р. 1971). Оскар за «Далласский клуб покупателей». Джокер («Отряд самоубийц»), лидер группы Thirty Seconds to Mars.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3341818/pub_5ff205b2f906b16872fdfaa9_5ff20bd6d1a90641ca173a01/scale_1200">Картинка</a>',
              'Джеймс Франко (р. 1978). Номинация на Оскар за «127 часов». «Харви Милк», «Этот дурацкий мир», «Зелёный Шершень».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1900370/pub_5ff205b2f906b16872fdfaa9_5ff20bd6af142f0b177b3527/scale_1200">Картинка</a>',
              'Джейк Джилленхол (р. 1980). Номинация на Оскар («Горбатая гора»). «Стрингер», «Ультиматум Борна», «Донни Дарко».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3481765/pub_5ff205b2f906b16872fdfaa9_5ff20c31af142f0b177bc492/scale_1200">Картинка</a>',
              'Джереми Айронс (р. 1948). Оскар за «Изнанку судьбы». Голос Скара («Король Лев»), Альфред в «Бэтмен против Супермена».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1707183/pub_5ff205b2f906b16872fdfaa9_5ff20c32f906b1687208097f/scale_1200">Картинка</a>',
              'Джин Хэкман (р. 1930). Два Оскара. «Французский связной», «Непрощённый», «Супермен» (Лекс Лютор). Легенда.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2142605/pub_5ff205b2f906b16872fdfaa9_5ff20c32bb14d54ffbb5ca9f/scale_1200">Картинка</a>',
              'Джон Войт (р. 1938). Оскар за «Возвращение домой». «Полуночный ковбой», «Миссия невыполнима», отец Анджелины Джоли.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2424254/pub_5ff205b2f906b16872fdfaa9_5ff20c32bb14d54ffbb5caa0/scale_1200">Картинка</a>',
              'Джефф Бриджес (р. 1949). Оскар за «Сумасшедшее сердце». «Большой Лебовски» (Чувак), «Железный человек» (Обадайя Стейн).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1930771/pub_5ff205b2f906b16872fdfaa9_5ff20c33f906b16872080b42/scale_1200">Картинка</a>',
              'Джо Пеши (р. 1943). Оскар за «Славные парни». «Однажды в Америке», «Казино», «Джокер» (1970-е).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1578906/pub_5ff205b2f906b16872fdfaa9_5ff20c33fe4e686f6a47b82f/scale_1200">Картинка</a>',
              'Джеки Чан (р. 1954). Мастер кунг-фу и комедийных трюков. «Пьяный мастер», «Час пик», «Полицейская история». Премия Оскар за вклад.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3396902/pub_5ff205b2f906b16872fdfaa9_5ff20c35f906b16872080e21/scale_1200">Картинка</a>',
              'Джордж Клуни (р. 1961). Два Оскара (актёр «Сириана», продюсер «Арго»). «Одиннадцать друзей Оушена», «От заката до рассвета».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3481765/pub_5ff205b2f906b16872fdfaa9_5ff20c37af142f0b177bcbdf/scale_1200">Картинка</a>',
              'Джуд Лоу (р. 1972). Дважды номинант на Оскар. «Талантливый мистер Рипли», «Шерлок Холмс» (Ватсон), «Молодой Папа».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3446567/pub_5ff205b2f906b16872fdfaa9_5ff20c37d1a90641ca17cefa/scale_1200">Картинка</a>',
              'Дон Чидл (р. 1964). Оскар за «Отель Руанда» (номинация). Мартинез в «Одиннадцати друзьях Оушена», Роудс в MCU («Железный человек 2»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3765046/pub_5ff205b2f906b16872fdfaa9_5ff20c37af142f0b177bcc83/scale_1200">Картинка</a>',
              'Джон Кьюсак (р. 1966). «Быть Джоном Малковичем», «Крупная рыба», «1408», культовый персонаж ромкомов («Всё могу»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2458644/pub_5ff205b2f906b16872fdfaa9_5ff20c38f906b168720812d9/scale_1200">Картинка</a>',
              'Дэниел Рэдклифф (р. 1989). Гарри Поттер (2001–2011). После франшизы снимается в артхаусе («Швейцарский нож», «Абсолютная власть»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3524431/pub_5ff205b2f906b16872fdfaa9_5ff20c38f906b1687208137c/scale_1200">Картинка</a>',
              'Дэниел Дэй-Льюис (р. 1957). Трёхкратный Оскар («Моя левая нога», «Нефть», «Линкольн»). Перфекционист, метод-актёр.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3683451/pub_5ff205b2f906b16872fdfaa9_5ff20c3cf906b16872081a33/scale_1200">Картинка</a>',
              'Дэнни ДеВито (р. 1944). Миниатюрный комик. «Пролетая над гнездом кукушки», «Такси», «В Филадельфии всегда солнечно» (Фрэнк).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1594643/pub_5ff205b2f906b16872fdfaa9_5ff20c3daf142f0b177bd4cd/scale_1200">Картинка</a>',
              'Иэн МакКеллен (р. 1939). Гэндальф («Властелин колец»), Магнето («Люди Икс»). Легенда театра и кино.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3588827/pub_5ff205b2f906b16872fdfaa9_5ff20c3dfe4e686f6a47c791/scale_1200">Картинка</a>',
              'Дэниел Крейг (р. 1968). Джеймс Бонд (2006–2021). «Казино „Рояль“», «Девушка с татуировкой дракона», «Достать ножи».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1712971/pub_5ff205b2f906b16872fdfaa9_5ff20c3ef906b16872081d0a/scale_1200">Картинка</a>',
              'Дуэйн Джонсон (р. 1972). «Скала». Бывший рестлер, король экшн-комедий («Форсаж», «Джуманджи», «Чёрный Адам»).'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2436983/pub_5ff205b2f906b16872fdfaa9_5ff20c3ebb14d54ffbb5de0f/scale_1200">Картинка</a>',
              'Жерар Депардье (р. 1948). Легенда французского кино. «Сирано де Бержерак», «Зелёная карта», «Астерикс и Обеликс».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3446567/pub_5ff205b2f906b16872fdfaa9_5ff20de3f906b168720aab04/scale_1200">Картинка</a>',
              'Кевин Костнер (р. 1955). Два Оскара (режиссёр «Танцев с волками»). «Телохранитель», «Дж. Ф. К.», «Йеллоустоун».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3756876/pub_5ff205b2f906b16872fdfaa9_5ff20e0bf906b168720ae65a/scale_1200">Картинка</a>',
              'Кевин Спейси (р. 1959). Два Оскара («Подозрительные лица», «Красота по-американски»). Фрэнк Андервуд («Карточный домик»).')) AS cards(front_side, back_side);


INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🍄 Самые распространенные грибы (определи по фото)', 1, true,
        'Съедобные, условно-съедобные и ядовитые грибы с описанием. Важно для грибников. 💡 Картинки отображаются только во время тренировки.')
;


INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id
        FROM card_collection
        WHERE name = '🍄 Самые распространенные грибы (определи по фото)'
        LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Belyj-grib-trevel.jpg">Картинка</a>',
              'Белый гриб (боровик). Съедобный, деликатес. Шляпка коричневая, ножка толстая белая, мякоть не темнеет. Растёт в хвойных и лиственных лесах с июня по октябрь. Лучше всего сушить, жарить, варить супы.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Borovik-trevel.jpg">Картинка</a>',
              'Боровик (разновидность белого). Съедобный. Шляпка каштановая с вишнёвым отливом, ножка крепкая. Растёт в сосновых борах с июня по сентябрь. Годится для сушки, жарки, варки, маринования.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Podosinovik.jpg">Картинка</a>',
              'Подосиновик. Съедобный. Шляпка красно-коричневая, ножка с тёмными чешуйками, мякоть на срезе синеет. Растёт под осинами и тополями с июня по октябрь. Хорош в жареном, варёном виде, можно солить и сушить.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Podberezovik.jpg">Картинка</a>',
              'Подберёзовик. Съедобный. Шляпка коричневая (от светлой до тёмной), ножка с чёрными чешуйками, мякоть не синеет. Растёт в березовых лесах с июня по октябрь. Употребляют жареным, варёным, маринованным, сушёным.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Lisichki-dlya-Trevela.png">Картинка</a>',
              'Лисички. Съедобные. Ярко-жёлтые или оранжевые, шляпка волнистая, пластинчатые складки спускаются на ножку. Растут во мху, среди листвы с июня по октябрь. Жарят, варят, солят, маринуют. Не бывают червивыми.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Shampinony.jpg">Картинка</a>',
              'Шампиньоны. Съедобные. Шляпка белая или кремовая, пластинки розовеют, затем темнеют. Растут на богатой перегноем почве, лугах, в садах с мая по октябрь. Можно есть сырыми, жарить, запекать, тушить.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Dozhdevik.jpg">Картинка</a>',
              'Дождевик (молодой). Съедобный (мякоть белая и упругая). Грушевидной формы, грязно-белый с колючими бугорками. Растёт в лиственных лесах, на полянах с июня по сентябрь. Жарят, варят, супы.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/maslyata.jpg">Картинка</a>',
              'Маслята. Съедобные. Шляпка скользкая, маслянистая, жёлто-коричневая, с легко снимающейся кожицей. Растут в сосновых лесах с июня по октябрь. Жарят, маринуют, солят, сушат (предварительно снимая кожицу).'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Opyata.jpg">Картинка</a>',
              'Опята. Съедобные. Растут на пнях группами. Ножка тонкая с плёнчатым кольцом, шляпка кремово-коричневая. Сезон – осень. Варят, жарят, маринуют, солят, сушат.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Gruzdi.jpg">Картинка</a>',
              'Грузди. Условно-съедобные (требуют вымачивания). Шляпка белая с опущенным краем, млечный сок горький. Растут в березовых и смешанных лесах с июля по сентябрь. Традиционно солят после вымачивания.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Podgruzdki-Trevel.png">Картинка</a>',
              'Подгруздки. Съедобные. Похожи на грузди, но шляпка сухая, без млечного сока. Растут в лиственных лесах с июля по октябрь. Отваривают, затем жарят, тушат, солят, маринуют.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Veshenki-.jpg">Картинка</a>',
              'Вешенки. Съедобные. Шляпка веерообразная, серая или бежевая, растут пучками на пнях и валежнике. Сезон – с весны до осени. Жарят, тушат, маринуют, добавляют в супы.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Smorchki.jpg">Картинка</a>',
              'Сморчки. Условно-съедобные (требуют длительной варки). Шляпка ячеистая, полая внутри, коричневая. Растут в лесах, парках весной (апрель-май). После отваривания жарят, тушат, сушат.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Ryzhik.jpg">Картинка</a>',
              'Рыжик. Съедобный. Шляпка оранжевая с зеленоватыми пятнами, млечный сок оранжевый. Растёт в сосновых лесах с июля по октябрь. Жарят, солят, маринуют, едят сырыми.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Berezovaya-chaga.jpg">Картинка</a>',
              'Березовая чага. Лекарственный гриб, несъедобный в обычном понимании. Нарост чёрного цвета с оранжевой серединой на берёзах. Растёт круглый год. Используют для чая и настоек (не варить).'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Ryadovka.jpg">Картинка</a>',
              'Рядовка (серая). Съедобная (но есть ядовитые виды!). Шляпка мышино-серая или серо-коричневая, волокнистая. Растёт группами в сосновых лесах с сентября по октябрь. Жарят, варят, солят, маринуют.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Trjufel.jpg">Картинка</a>',
              'Трюфель. Съедобный, деликатес. Растёт под землёй, клубневидный, чёрный или белый. Встречается в дубравах. Сезон – осень. Натирают в блюда, добавляют в соусы, пасту.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Lozhnye-opyata.jpg">Картинка</a>',
              'Ложные опята (кирпично-красные, серно-жёлтые). Условно-съедобные (горькие) или ядовитые. Отличаются отсутствием кольца на ножке, более яркой окраской. Растут на пнях. Лучше не собирать.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Blednaya-poganka.jpg">Картинка</a>',
              'Бледная поганка. Смертельно ядовита! Шляпка зеленоватая или белая, с кольцом на ножке и вольвой. Растёт в лиственных лесах с августа по октябрь. НЕ СОБИРАТЬ!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Muhomor-vonjuchij.jpg">Картинка</a>',
              'Мухомор вонючий (белая поганка). Смертельно ядовит. Белый гриб с неприятным запахом (хлорка). Шляпка коническая, ножка с кольцом и вольвой. Растёт в хвойных и смешанных лесах. НЕ СОБИРАТЬ!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Muhomor-krasnyj.jpg">Картинка</a>',
              'Мухомор красный. Ядовит (галлюциноген). Красная шляпка с белыми пятнами. Растёт в лесах с июля по октябрь. Не употреблять в пищу.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Muhomor-yarko-zhjoltyj.jpg">Картинка</a>',
              'Мухомор ярко-жёлтый. Ядовит. Шляпка жёлтая или розовато-жёлтая с белыми чешуйками. Растёт в лесах с июля по сентябрь. Вызывает галлюцинации и расстройство ЖКТ.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Muhomor-panternyj.jpg">Картинка</a>',
              'Мухомор пантерный. Ядовит. Шляпка коричневая с белыми пятнами (как у пантеры). Растёт в лесах. Содержит токсины, вызывающие судороги. Не собирать!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Zhelchnyj-grib.jpg">Картинка</a>',
              'Жёлчный гриб (горчак). Несъедобный (горький). Двойник белого и подберёзовика. Трубчатый слой розовый, мякоть горчит. Растёт в хвойных лесах. Не готовить.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Galerina-okajmlennaya.jpg">Картинка</a>',
              'Галерина окаймлённая. Смертельно ядовита. Маленький коричневый гриб на пнях, похож на опёнка, но с кольцом. Содержит аматоксины. НЕ СОБИРАТЬ!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Pautinnik-krasivejshij.jpg">Картинка</a>',
              'Паутинник красивейший. Смертельно ядовит. Оранжево-коричневый, похож на лисичку, но с ржавыми пластинками и запахом редиски. Вызывает почечную недостаточность.'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Cvinushka-tonkaya.jpg">Картинка</a>',
              'Свинушка тонкая. Ядовита (накапливает токсины). Шляпка охристая, вдавленная. Растёт в лесах. Вызывает аллергию и разрушение эритроцитов. Не собирать!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Leopita-yadovitaya.jpg">Картинка</a>',
              'Лепиота ядовитая. Смертельно ядовита. Белый гриб с чешуйчатой шляпкой и двойным кольцом на ножке. Запах резины. Растёт в лесах. НЕ СОБИРАТЬ!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/Lozhnye-smorchki.jpg">Картинка</a>',
              'Строчок (ложный сморчок). Ядовит. Шляпка красновато-коричневая, мозговидная, полая не полностью. Растёт весной. Содержит гиротоксин. Опасно!'),
             ('<a href="https://svoe-zagorodom.ru/blog/wp-content/uploads/2024/08/lozhnye-lisichki.jpg">Картинка</a>',
              'Ложная лисичка (говорушка оранжевая). Условно-съедобна после отваривания, но часто вызывает отравления. Более яркая, оранжевая, с ровными краями шляпки и тонкой ножкой. Не рекомендуется.')) AS cards(front_side, back_side);



INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🏔️ 50 самых красивых мест мира (определи по фото)', 1, true,
        'Подборка потрясающих локаций: от лавандовых полей Прованса до пещер светлячков в Новой Зеландии. 💡 Картинки отображаются только во время тренировки.')
;


INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id
        FROM card_collection
        WHERE name = '🏔️ 50 самых красивых мест мира (определи по фото)'
        LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbe7dc60fd03712282ddae/scale_1200">Картинка</a>',
              '🌷 Парк Кёкенхоф (Голландия). Нидерланды известны радужными полями тюльпанов. Ежегодно здесь высаживают миллионы луковиц. Лучшее время для посещения – середина апреля, когда цветы полностью распускаются.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4475640/pub_63cbe7501b0342228a6ca4db_63cbe7efa0298400957d5990/scale_1200">Картинка</a>',
              '🎈 Каппадокия (Турция). Турецкая местность, где из скал высечены целые города. Когда небо наполнено воздушными шарами, уровень красоты этого места достигает облаков.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2046228/pub_63cbe7501b0342228a6ca4db_63cbe803097158269d61f061/scale_1200">Картинка</a>',
              '🎋 Арасияма (Киото, Япония). Безмятежная красота бамбукового леса в районе Арасияма представляет собой прекрасное зрелище.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5022911/pub_63cbe7501b0342228a6ca4db_63cbe822ef8ec52eb16162fd/scale_1200">Картинка</a>',
              '🪞 Салар де Уюни (Боливия). Отражающая поверхность крупнейшей в мире соляной шахты похожа на живое зеркало. Словно её взяли прямиком из воображения Сальвадора Дали.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbe96ccd8bcc467ae1602d/scale_1200">Картинка</a>',
              '🏜️ Брайс-Каньон (Юта, США). Слоистые красные и оранжевые каменные столбы, называемые худу, делают это место обязательным для туристов и фотографов.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3523766/pub_63cbe7501b0342228a6ca4db_63cbe97db93d2b437e4ae604/scale_1200">Картинка</a>',
              '🌾 Мукангчай (Вьетнам). Одно из самых захватывающих дух мест во Вьетнаме. Здесь можно увидеть террасные рисовые поля, окружённые горными ландшафтами.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234055/pub_63cbe7501b0342228a6ca4db_63cbe923a1165f4480a4b843/scale_1200">Картинка</a>',
              '❄️ Ватнайокудль (Исландия). Самый большой ледник в Исландии. Ландшафт под его поверхностью выглядит как другой мир, наполненный ледяными пещерами, каньонами и вулканами.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3704848/pub_63cbe7501b0342228a6ca4db_63cbe9a1d54bf059ee4ab6f2/scale_1200">Картинка</a>',
              '🗿 Пирамиды Гизы (Египет). Три великие пирамиды — загадочные архитектурные чудеса, построенные во времена Хеопса.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4719986/pub_63cbe7501b0342228a6ca4db_63cbe9bd60fd03712286ad6a/scale_1200">Картинка</a>',
              '🦒 Дельта Окаванго (Ботсвана). Пышный пейзаж похож на настоящий Эдем, где в дикой природе свободно бродят гепарды, зебры, буйволы и носороги.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5240189/pub_63cbe7501b0342228a6ca4db_63cbe9d5a1165f4480a61e07/scale_1200">Картинка</a>',
              '🏜️ Пустыня Намиб (Намибия). Красные дюны и скелетные деревья делают Намибию самым близким местом к Марсу по внешнему виду. Здесь снимали «Безумный Макс: Дорога ярости».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbe9e66f025e1b0b1a8128/scale_1200">Картинка</a>',
              '🏔️ Скалы Мохер (Ирландия). Это приморское чудо, также известное как Скалы Безумия из фильма «Принцесса-невеста», находится недалеко от города Голуэй.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbe9f642043747b1cab3b8/scale_1200">Картинка</a>',
              '🏖️ Пляж пещеры Бенагил (Алгарве, Португалия). Южное побережье Португалии покрыто прекрасными пляжами и пещерами, включая знаменитый пещерный пляж Бенагил.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5298381/pub_63cbe7501b0342228a6ca4db_63cbea11cd8bcc467ae28559/scale_1200">Картинка</a>',
              '🌸 Цветочный парк в Асикаге (Япония). Глициниевые деревья красиво цветут несколько недель в начале каждой весны, украшая парк пастельно-розовыми и пурпурными цветами.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/901899/pub_63cbe7501b0342228a6ca4db_63cbea24823874155413ccb8/scale_1200">Картинка</a>',
              '🏯 Паро Такцанг (Бутан). Монастырь «Гнездо Тигра» возвышается над скалой на высоте более 3 км. Виды на долину Паро поражают воображение.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5233714/pub_63cbe7501b0342228a6ca4db_63cbea3eb93d2b437e4c6461/scale_1200">Картинка</a>',
              '🍃 Чайная плантация Колуккумалай (Муннар, Индия). Расположена почти в 2,5 км над уровнем моря — самая высоко расположенная чайная плантация в мире.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbea5946766a73d24845c1/scale_1200">Картинка</a>',
              '🌊 Большая голубая дыра (Белиз). Впадина диаметром около 130 метров посреди кораллового рифа. В глубинах — массивные известняковые сталактиты и сталагмиты.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1947084/pub_63cbe7501b0342228a6ca4db_63cbea777775357d86de6ff7/scale_1200">Картинка</a>',
              '🛶 Венеция (Италия). Из всех удивительных городов Италии залитые солнцем каналы Венеции обладают наибольшим очарованием.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5240189/pub_63cbe7501b0342228a6ca4db_63cbea89097158269d668b86/scale_1200">Картинка</a>',
              '⛵ Бухта Халонг (Вьетнам). Ценится своими голубыми водами и серией известняковых островов, покрытых тропической растительностью.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbea986f025e1b0b1be823/scale_1200">Картинка</a>',
              '🌾 Моравские поля (Чехия). Пейзажи Моравских полей созданы будто мазками гениального живописца. Эти пастельные холмы абсолютно реальны.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3768331/pub_63cbe7501b0342228a6ca4db_63cbeaa860fd037122887ac3/scale_1200">Картинка</a>',
              '🏝️ Побережье На Пали (Кауаи, Гавайи). Одно из самых красивых береговых линий в мире. Открывается только с вертолёта, катамарана или после утомительной прогулки.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbeac84f09cf41b3609db0/scale_1200">Картинка</a>',
              '🦁 Национальный парк Серенгети (Танзания). Идеальное место для африканских приключений.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbead7b5a083312e2c4d6f/scale_1200">Картинка</a>',
              '💜 Лавандовые поля (Прованс, Франция). Бесконечные поля лаванды делают Прованс одним из самых красивых (и самых ароматных) мест во Франции.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5233119/pub_63cbe7501b0342228a6ca4db_63cbeadfef8ec52eb1665d8a/scale_1200">Картинка</a>',
              '🏝️ Фернандо де Норонья (Бразилия). Архипелаг из 21 острова с водопадами, высокими скалами, белым песком и ограниченным количеством туристов.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4120518/pub_63cbe7501b0342228a6ca4db_63cbeaf360fd037122890efd/scale_1200">Картинка</a>',
              '✨ Полярный круг. От северного сияния в Швеции до ледников у побережья Гренландии — всегда кажется скрытым раем.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbeafc4e549275cbec210f/scale_1200">Картинка</a>',
              '🏛️ Мачу-Пикчу (Перу). Панорамный вид и извилистые загадочные каменные стены — выдающееся подтверждение всемирной известности этого места.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbeb0d287071113e3d9027/scale_1200">Картинка</a>',
              '🏞️ Гранд-Каньон (Аризона, США). Одно из семи природных чудес света. Более 5 миллионов человек ежегодно посещают его.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3630864/pub_63cbe7501b0342228a6ca4db_63cbeb2460fd0371228978f6/scale_1200">Картинка</a>',
              '🕌 Самарканд (Узбекистан). Конечная остановка Шёлкового пути, отличающаяся замысловатыми узорами на зданиях и красочно одетыми местными жителями.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbeb366f025e1b0b1d1ae6/scale_1200">Картинка</a>',
              '✨ Пещеры светлячков (Вайтомо, Новая Зеландия). Тысячи светящихся личинок освещают пещеры, делая их похожими на подземный Млечный Путь.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1950904/pub_63cbe7501b0342228a6ca4db_63cbeb43a1165f4480a8ea18/scale_1200">Картинка</a>',
              '💧 Памуккале (Денизли, Турция). Ярусные бассейны, окружённые снегом и замёрзшими водопадами, но вода в них тёплая и подходит для купания.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3753737/pub_63cbe7501b0342228a6ca4db_63cbeb55e1707b4b3d8a32e2/scale_1200">Картинка</a>',
              '🌴 Долина Кокора (Киндио, Колумбия). Здесь находятся самые высокие пальмы (palma de cera), выглядящие эффектно на фоне туманных холмов.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/2749135/pub_63cbe7501b0342228a6ca4db_63cbebb1311d1c47a6208ecd/scale_1200">Картинка</a>',
              '🇬🇷 Ия (Санторини, Греция). Небольшая деревня поражает белыми зданиями с ярко-синими крышами на фоне вулканического залива.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbebd24f09cf41b362c18c/scale_1200">Картинка</a>',
              '🏛️ Петра (Иордания). Древний город, известный зданиями, высеченными прямо в скалах. Здесь снимали сцену с Святым Граалем из «Индианы Джонса».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5316610/pub_63cbe7501b0342228a6ca4db_63cbebe160fd0371228af46f/scale_1200">Картинка</a>',
              '💚 Озеро Блед (Словения). Изумрудно-зелёная гладь летом или покрытая снегом на фоне Юлийских Альп зимой — живописная красота.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbec02c965020e5875b4ae/scale_1200">Картинка</a>',
              '🏴󠁧󠁢󠁳󠁣󠁴󠁿 Остров Скай (Шотландия). Его воды и зелёные холмы делают остров Скай местом, где рождаются мечты.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3311877/pub_63cbe7501b0342228a6ca4db_63cbec104e549275cbee0bc1/scale_1200">Картинка</a>',
              '🌸 Намакваленд (Южная Африка). С приходом весны местность покрывается оранжевыми, белыми и радужными цветами, становясь временной туристической достопримечательностью.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5332912/pub_63cbe7501b0342228a6ca4db_63cbec2ce3f11746496a6599/scale_1200">Картинка</a>',
              '🧱 Великая Китайская стена (Пекин, Китай). Длина более 19 000 км, ей тысячи лет, её можно увидеть из космоса.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3768331/pub_63cbe7501b0342228a6ca4db_63cbec38ef8ec52eb168d35b/scale_1200">Картинка</a>',
              '🛕 Баган (Мьянма). Древний город с тысячами ступ и храмов, возвышающихся над окружающими лесами.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbec4da1165f4480aaf6ae/scale_1200">Картинка</a>',
              '🌲 Национальный парк Редвуд (Калифорния, США). 2000-летние гиганты-секвойи высотой почти 100 футов.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5231221/pub_63cbe7501b0342228a6ca4db_63cbec5842043747b1cf0094/scale_1200">Картинка</a>',
              '🐠 Большой Барьерный риф и пляж Уайтхейвен (Австралия). Крупнейшая живая структура на Земле, видимая из космоса, и один из самых красивых пляжей в мире.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4961935/pub_63cbe7501b0342228a6ca4db_63cbec70287071113e401739/scale_1200">Картинка</a>',
              '🗻 Улуру (Австралия). 700-миллионолетней скале можно любоваться с воздуха на шаре, катаясь на мотоцикле по пустыне или на закате.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3614639/pub_63cbe7501b0342228a6ca4db_63cbec8d8238741554183262/scale_1200">Картинка</a>',
              '⛰️ Милфорд-Бэй (Новая Зеландия). Гористый фьорд, где можно воссоздать любимые сцены из «Властелина колец».'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5234501/pub_63cbe7501b0342228a6ca4db_63cbecac6f025e1b0b200481/scale_1200">Картинка</a>',
              '⛰️ Улинъюань (Чжанцзяцзе, Китай). Тысячи колонн из песчаника, которые выше половины Эмпайр-Стейт-Билдинг.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4392090/pub_63cbe7501b0342228a6ca4db_63cbed25a02984009586d43b/scale_1200">Картинка</a>',
              '🏔️ Денали (Аляска, США). Бывшая гора Мак-Кинли — высочайшая вершина Северной Америки.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/5372100/pub_63cbe7501b0342228a6ca4db_63cbecf0ef8ec52eb16a2314/scale_1200">Картинка</a>',
              '🛕 Ангкор-Ват (Сием-Рип, Камбоджа). Самый большой и впечатляющий храмовый комплекс Азии.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4594882/pub_63cbe7501b0342228a6ca4db_63cbee084e549275cbf1a237/scale_1200">Картинка</a>',
              '🏔️ Национальный парк Торнгат-Маунтинс (Лабрадор, Канада). Земля белых медведей, карибу, ледников, фьордов и горных цепей.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/3412469/pub_63cbe7501b0342228a6ca4db_63cbee44287071113e436f9d/scale_1200">Картинка</a>',
              '🏝️ Боракай (Филиппины). Благодаря пологим берегам и захватывающим дух закатам назван самым красивым островом в мире.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1587994/pub_63cbe7501b0342228a6ca4db_63cbee4d311d1c47a625ad0a/scale_1200">Картинка</a>',
              '🌳 Сокотра (Йемен). Выглядит как часть далёкой планеты. Космические драконьи деревья (Dracaena cinnabari) — визитная карточка острова.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1704967/pub_63cbe7501b0342228a6ca4db_63cbee5a6f025e1b0b235205/scale_1200">Картинка</a>',
              '🌋 Вулкан Бромо (Восточная Ява, Индонезия). Самый известный вулкан национального парка Бромо-Тенгер-Семеру с потрясающими видами на восходе.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/4956378/pub_63cbe7501b0342228a6ca4db_63cbee68b93d2b437e54b914/scale_1200">Картинка</a>',
              '🏔️ Национальный парк Торрес-дель-Пайне (Патагония, Чили). Высокие горы, голубые ледники и мифические озёра — всё, что делает Патагонию захватывающей.'),
             ('<a href="https://avatars.dzeninfra.ru/get-zen_doc/1587994/pub_63cbe7501b0342228a6ca4db_63cbeea0e1707b4b3d90b936/scale_1200">Картинка</a>',
              '🏝️ Курильские острова (Россия и Япония). Цепь из 56 островов с горячими источниками, десятками действующих вулканов, от высокогорной тундры до пышных лугов.')) AS cards(front_side, back_side);


