INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('😼 Породы кошек (в картинках)', 1, true,
        'Более 40 пород кошек с уникальными фото. Поможет запомнить, как выглядят разные кошки. 💡 Картинки отображаются только во время тренировки.')
;


INSERT INTO card (user_id, card_collection_id, front_side, back_side)
SELECT 1,
       (SELECT card_collection_id FROM card_collection WHERE name = '😼 Породы кошек (в картинках)' LIMIT 1),
       front_side,
       back_side
FROM (VALUES ('<a href="https://hvost.news/optimpictures/images/5855348d840f38631355330a2c26db2d/870b4a4cb6851923f56e0706fd8a5cb8.jpg.webp">Картинка</a>',
              'Мейн-кун. Естественная порода США (штат Мэн). Крупная, кисточки на ушах, густая шерсть, дружелюбный «нежный великан».'),
             ('<a href="https://hvost.news/optimpictures/images/d712b7ece398289ec2e4be13574c095d/1baf9fffdacdf759cdcd257cac376e2c.jpg.webp">Картинка</a>',
              'Британская короткошёрстная. Выведена в Великобритании (XIX век). Плюшевая шерсть, круглые щёки, спокойная, независимая.'),
             ('<a href="https://hvost.news/optimpictures/images/4778c3dc669815dbaffc467b12d38200/shotlandskaja_vislouhaja.jpg.webp">Картинка</a>',
              'Шотландская вислоухая (скоттиш-фолд). Появилась в Шотландии (1961). Висячие уши, круглые глаза, добрая, любит людей.'),
             ('<a href="https://hvost.news/optimpictures/images/8aa0f0d791cc1b04cb8aed64c024e853/iStock_536505097.jpg.webp">Картинка</a>',
              'Канадский сфинкс. Выведен в Канаде (1966). Практически нет шерсти, большие уши, очень ласковый, нуждается в тепле.'),
             ('<a href="https://hvost.news/optimpictures/images/3b6c0b443bbdfd054d76d6fef9811660/43f740b7f9ac051ceb9d460beb57d196.jpg.webp">Картинка</a>',
              'Бенгальская. Гибрид азиатской леопардовой кошки и домашней (США, 1960-е). Окрас «леопард», активная, любит воду.'),
             ('<a href="https://hvost.news/optimpictures/images/3ee231a7bd9b8c94ec629ad0a5de6b8b/cc8b4cbeb208f4be5379de4ce480a6ec.jpg.webp">Картинка</a>',
              'Персидская. Древняя порода (Персия, Иран). Очень длинная шерсть, приплюснутая морда, спокойная, требует ухода.'),
             ('<a href="https://hvost.news/optimpictures/images/3cacf65f9a1e046df09ccac03909d8e0/6f9f92f1c4f9d08a8bca5cd924f8eb79.jpg.webp">Картинка</a>',
              'Сиамская. Древняя тайская порода (храмовые кошки). Кремовое тело, тёмные точки (лапы, морда), голубые глаза, голосистая.'),
             ('<a href="https://hvost.news/optimpictures/images/74c266323480ad5b53d92fd622ea6ea1/abissinskaja_poroda_koshek.jpg.webp">Картинка</a>',
              'Абиссинская. Происходит из Эфиопии (бывшая Абиссиния). Тикированный окрас, уши большие, очень активная, умная.'),
             ('<a href="https://hvost.news/optimpictures/images/4dc7635a95791abfec23dff9c13c3d65/c3e5026a95207a4687a3330ac84344e8.jpg.webp">Картинка</a>',
              'Русская голубая. Естественная порода России (Архангельск). Голубовато-серая шерсть, зелёные глаза, застенчивая, нежная.'),
             ('<a href="https://hvost.news/optimpictures/images/12cb23dfdac5fa080125a770bfff4949/vostochnaja_korotkosherstnaja.jpg.webp">Картинка</a>',
              'Ориентальная короткошёрстная. Выведена в Великобритании (1970-е). Уши-локаторы, стройное тело, общительная, «разговорчивая».'),
             ('<a href="https://hvost.news/optimpictures/images/653cf696a4018a886129c2475d422df9/08a1167da1df1d0399d64352985dd50d.jpg.webp">Картинка</a>',
              'Рэгдолл. Выведен в США (1960-е). Голубые глаза, полудлинная шерсть, расслабляется на руках («тряпичная кукла»).'),
             ('<a href="https://hvost.news/optimpictures/images/39cd6039993244074f0dd4f31e014ce1/66164afca79f3357c7dda0b175f5f07d.jpg.webp">Картинка</a>',
              'Экзотическая короткошёрстная (экзот). Выведена в США (1960-е) как короткошёрстный перс. Плюшевый, кругломордый, спокойный.'),
             ('<a href="https://hvost.news/optimpictures/images/d712b7ece398289ec2e4be13574c095d/1ba66276cbb4ea978f1e6135851805fb.jpeg.webp">Картинка</a>',
              'Девон-рекс. Появился в Англии (1960). Кудрявая короткая шерсть, большие уши, эльфийский вид, игривый, общительный.'),
             ('<a href="https://hvost.news/optimpictures/images/3eb4d002d126b9f3aef8e7ed753946ca/dd54f85fac94a15e83bf444e79798f38.jpg.webp">Картинка</a>',
              'Корниш-рекс. Выведен в Англии (1950). Волнистая шерсть, изящное тело, любопытный, любит высоту.'),
             ('<a href="https://hvost.news/optimpictures/images/d5ee53774bd16bffdc710d97f0e76fe0/8eed0ee6004c67ee21e22fdb77e01fcd.jpg.webp">Картинка</a>',
              'Турецкая ангора. Древняя порода Турции (Анкара). Белая длинная шерсть, голубые или разноглазые, изящная, умная.'),
             ('<a href="https://hvost.news/optimpictures/images/d238091ddca49bc75a3c04f126d793e6/birmanskaja_svjashhennaja.jpg.webp">Картинка</a>',
              'Бурма (бирманская священная). Выведена во Франции (XX век). Персидского типа, белые «носочки», голубые глаза, ласковая.'),
             ('<a href="https://hvost.news/optimpictures/images/bfb787eb020713f3e1f85181f5abe411/kuril_skij_bobtejl.jpg.webp">Картинка</a>',
              'Курильский бобтейл. Естественная порода с Курильских островов. Короткий хвост-помпон, похожа на рысь, охотничья.'),
             ('<a href="https://hvost.news/optimpictures/images/0143fb4e2a3e77415c00160cecf21490/d6a373d4165b7e94a201e7bc93b07e66.jpeg.webp">Картинка</a>',
              'Сибирская (в т.ч. невская маскарадная). Естественная порода России. Полудлинная шерсть, гипоаллергенная, сильная, ловкая.'),
             ('<a href="https://hvost.news/optimpictures/images/bf7a863a8e51d3fada4191afd13f7ed5/e07b8320fad5ac0cd2a90abf4dba1da2.jpg.webp">Картинка</a>',
              'Норвежская лесная. Древняя порода Скандинавии. Двойная водоотталкивающая шерсть, кисточки на ушах, дружелюбная.'),
             ('<a href="https://hvost.news/optimpictures/images/8866d8c20fbad1743895dab37d1c371a/1d8a44dcf6b5d9670ad9d3276a0ba895.jpg.webp">Картинка</a>',
              'Мэнкс (бесхвостая). Древняя порода острова Мэн (Ирландское море). Отсутствие хвоста, круглая голова, собачий характер.'),
             ('<a href="https://hvost.news/optimpictures/images/765bd9b4dbacba1c3f7e4523d3ba3b40/064eb8b681b303cb4f5ffb95bd76ccee.jpg.webp">Картинка</a>',
              'Сомалийская. Длинношёрстная мутация абиссинской (США, 1960-е). Тикированный окрас, пушистый хвост, активная, игривая.'),
             ('<a href="https://hvost.news/optimpictures/images/5ae93a78a02c8642b46deb8ee627e2b1/cf7833986cde872a19ede02de22c4434.jpg.webp">Картинка</a>',
              'Бомбейская. Выведена в США (1970-е) как «мини-пантера». Чёрная шерсть, медные глаза, спокойная, ласковая.'),
             ('<a href="https://hvost.news/optimpictures/images/10aa6b77b3005efe497944320f3dca63/chartrez.jpg.webp">Картинка</a>',
              'Шартрез. Древняя порода Франции. Голубоватая шерсть, шерстяной подшёрсток, тихая, любит уединение.'),
             ('<a href="https://hvost.news/optimpictures/images/8d1b48b19148a56722ed75d28d66162e/egipetskaja_mau.jpg.webp">Картинка</a>',
              'Египетская мау. Потомок древнеегипетских кошек. Пятнистый окрас, зелёные глаза, быстрая, голосистая.'),
             ('<a href="https://hvost.news/optimpictures/images/3d51e40f5def1b0aef914e84b0527451/koshka_porody_tojger.jpg.webp">Картинка</a>',
              'Тойгер. Выведен в США (1980-е) как «полосатый тигр». Полосатый окрас, мускулистое тело, дружелюбный, активный.'),
             ('<a href="https://hvost.news/optimpictures/images/4d3531fef1c3a721147115a283f55c5c/savanna_ashera.jpg.webp">Картинка</a>',
              'Саванна. Гибрид сервала и домашней кошки (США, 1980-е). Крупная, большие уши, пятнистая, преданная, активная.'),
             ('<a href="https://hvost.news/optimpictures/images/2023e412f9195070e26b995122bbc7d7/serengeti.jpg.webp">Картинка</a>',
              'Серенгети. Создана в США (1994) без крови диких кошек. Длинные ноги, большие уши, пятнистая, дружелюбная.'),
             ('<a href="https://hvost.news/optimpictures/images/c9575db7f6b65691c292caf376586d22/kot_ocicat.jpg.webp">Картинка</a>',
              'Оцикет. Выведен в США (1960-е) из сиамских и абиссинских. Пятнистый, мускулистый, общительный, похож на дикого.'),
             ('<a href="https://hvost.news/optimpictures/images/45ba203e41d8c26a4d5510f9ed80700b/tonkinskaja_koshka.jpg.webp">Картинка</a>',
              'Тонкинская. Канадская порода (1960-е, гибрид сиамской и бурманской). Аквамариновые глаза, шерсть норка, ласковая.'),
             ('<a href="https://hvost.news/optimpictures/images/165e1b3558768f5b96035d3024738721/burmilla.jpg.webp">Картинка</a>',
              'Бурмилла. Британская порода (1980-е, гибрид бурмы и перса). Серебристый тикированный окрас, зелёные глаза, нежная.'),
             ('<a href="https://hvost.news/optimpictures/images/c03412b57db98d4a073696502a835aa5/5d6e0953c2061ecaf20e4617be3e361e.jpg.webp">Картинка</a>',
              'Японский бобтейл. Древняя порода Японии. Короткий закрученный хвост, изящная, любит воду, «поющая».'),
             ('<a href="https://hvost.news/optimpictures/images/675e4c085ff52c87e1fef2d99e0eae4b/601de438def2599040fa77adbbe9321a.jpg.webp">Картинка</a>',
              'Селкирк-рекс. Выведен в США (1987). Густая кудрявая шерсть (от персидских и рексов), крупный, флегматичный.'),
             ('<a href="https://hvost.news/optimpictures/images/e8a4a81d56a2e445513ef5e19c0801f0/laperm.jpg.webp">Картинка</a>',
              'Лаперм. Американская порода (1980-е). Кудрявая мягкая шерсть, большие уши, любопытный, очень ласковый.'),
             ('<a href="https://hvost.news/optimpictures/images/848561f79b427d3565451a1129ab5b4e/uralskiy_reks.jpg.webp">Картинка</a>',
              'Уральский рекс. Естественная мутация на Урале (1988). Кудрявая шерсть, средний размер, дружелюбный, здоровый.'),
             ('<a href="https://hvost.news/optimpictures/images/e2d65a3d47e2e85faab0ec9892d1cb8c/aziatskaya_tabbi.jpg.webp">Картинка</a>',
              'Азиатская табби. Британская порода (1980-е, от бурмиллы). Тигровый или мраморный окрас, мускулистая, игривая.'),
             ('<a href="https://hvost.news/optimpictures/images/eaf6da2ab39cd5b348c6457da2970d75/12fd19e1374220bd0175b0a78c6b733f.jpg.webp">Картинка</a>',
              'Сингапурская. Карликовая порода из Сингапура. Коричневый тикированный окрас, огромные глаза, ласковая, тихая.'),
             ('<a href="https://hvost.news/optimpictures/images/065982f149305a27b8e803e422737e84/7f4ba645a4c2988c66486e668cf8198a.jpg.webp">Картинка</a>',
              'Американский бобтейл. Выведен в США (1960-е). Короткий хвост (1/3 длины), дикий окрас, дружелюбный, собачий характер.'),
             ('<a href="https://hvost.news/optimpictures/images/e921e696d8f8d4ddc9976b2995a4b0a6/evropejskaja_korotkosherstnaja_koshka.jpg.webp">Картинка</a>',
              'Европейская короткошёрстная. Аборигенная порода Европы. Крепкая, разнообразие окрасов, охотничий инстинкт, независимая.'),
             ('<a href="https://hvost.news/optimpictures/images/7dca8e6eac1c963c978dd957110f2464/tureckij_van.jpg.webp">Картинка</a>',
              'Турецкий ван. Древняя порода с озера Ван. Любит воду, белая с рыжими пятнами на голове и хвосте, энергичная.'),
             ('<a href="https://hvost.news/optimpictures/images/ce6dcbd8e67cc3ec68ed54beb7cf477d/havana.jpg.webp">Картинка</a>',
              'Гавана браун. Английская порода (1950-е). Шоколадная шерсть, зелёные глаза, любопытная, «разговорчивая».'),
             ('<a href="https://hvost.news/optimpictures/images/752d9c8fe4368c7a1dd39e332c9ac431/chauzi.jpg.webp">Картинка</a>',
              'Чаузи. Гибрид камышового кота и абиссинской (США, 1990-е). Крупная, дикий окрас, большие уши, активная.'),
             ('<a href="https://hvost.news/optimpictures/images/9ebe6c21bbce4e4f8e0497c20bb30f46/b97d73af8c4c6cd82ad8ce6fac8b582e.jpg.webp">Картинка</a>',
              'Бурманская (бурма). Выведена во Франции/США (1930-е). Шерсть норка, золотистые глаза, мускулистая, ласковая, умная.'),
             ('<a href="https://hvost.news/optimpictures/images/fa1c279d9b262a856acec9d8e73c8a31/ragamaffin.jpg.webp">Картинка</a>',
              'Рагамаффин. Родственник рэгдолла (США, 1990-е). Длинная шерсть, любые окрасы, очень ручной, «собачья» преданность.'),
             ('<a href="https://hvost.news/optimpictures/images/046e483e4e2e326ce8a96698fa567a1b/e8b5da77739247e0bd697f500e49912c.jpg.webp">Картинка</a>',
              'Кимрик (длинношёрстный мэнкс). Канадская порода (1960-е). Бесхвостая, полудлинная шерсть, игривая, прыгучая.')) AS cards(front_side, back_side);

INSERT INTO card_collection (name, author_id, is_public, description)
VALUES ('🐶 Породы собак (в картинках)', 1, true,
        'Коллекция из 50 популярных пород собак с фотографиями. Подходит для изучения внешности и названий пород. 💡 Картинки отображаются только во время тренировки.')
;

